// ALWAYS-RETURN, FIXED-SCHEMA VERSION
// Inputs:
// - members array discovered like your snippet (items[0].json or common variants)
// - approver text from $('update Approver #2').first().json.Approver2

// ---------- defaults & helpers ----------
const canon = (s) => (s ?? '').toLowerCase().trim();
const defaults = {
  ok: false,
  error: null,
  message: null,
  query: null,
  candidateCount: 0,
  userId: null,
  matchedField: null,
  matchedValue: null,
};
const done = (overrides = {}) => [{ json: { ...defaults, ...overrides } }];

// ---------- 0) Collect members (your discovery logic) ----------
let members = [];
if (Array.isArray(items?.[0]?.json)) members = items[0].json;
else if (Array.isArray(items?.[0]?.json?.data)) members = items[0].json.data;
else if (Array.isArray(items?.[0]?.json?.members)) members = items[0].json.members;
else if (Array.isArray(items) && items.length && items.every(i => i?.json && i.json.user)) {
  members = items.map(i => i.json);
} else if (Array.isArray($json)) {
  members = $json;
}

// ---------- 1) Read approver ----------
const raw = String($('Get Approval #1').first().json.data['Your Discord Name? (For first approval process)'] ?? '').trim();

// If we can't proceed, still return fixed-shape JSON
if (!members.length) {
  return done({
    error: 'members_not_found',
    message: 'Could not locate the members array on the incoming data.',
    query: raw || null,
    candidateCount: 0,
  });
}
if (!raw) {
  return done({
    error: 'empty_query',
    message: 'Approver is empty.',
    query: null,
    candidateCount: members.length,
  });
}

// ---------- 2) Short-circuit: mention or raw snowflake ID ----------
const mention = raw.match(/^<@!?(\d{17,20})>$/);
if (mention) {
  return done({
    ok: true,
    query: raw,
    candidateCount: members.length,
    userId: mention[1],
    matchedField: 'mention',
    matchedValue: raw,
  });
}
if (/^\d{17,20}$/.test(raw)) {
  return done({
    ok: true,
    query: raw,
    candidateCount: members.length,
    userId: raw,
    matchedField: 'id',
    matchedValue: raw,
  });
}

// ---------- 3) Build candidate list (ignore bots unless explicitly matched) ----------
const q = raw.replace(/^@+/, '').toLowerCase();
const ignoreBots = true;
let candidates = ignoreBots
  ? members.filter(m => !m?.user?.bot || canon(m?.user?.username) === q)
  : members;

// ---------- 4) Scoring + rules ----------
function score(m) {
  const nick  = canon(m?.nick);
  const user  = canon(m?.user?.username);
  const gname = canon(m?.user?.global_name);
  const nz = q.length > 0;
  return [
    nick === q,               // 0 exact:nick
    gname === q,              // 1 exact:global_name
    user === q,               // 2 exact:username
    nz && nick.startsWith(q), // 3 starts:nick
    nz && gname.startsWith(q),// 4 starts:global_name
    nz && user.startsWith(q), // 5 starts:username
    nz && nick.includes(q),   // 6 contains:nick
    nz && gname.includes(q),  // 7 contains:global_name
    nz && user.includes(q),   // 8 contains:username
  ];
}
const rules = [
  'exact:nick',
  'exact:global_name',
  'exact:username',
  'starts:nick',
  'starts:global_name',
  'starts:username',
  'contains:nick',
  'contains:global_name',
  'contains:username',
];

// ---------- 5) Select best match ----------
let picked = null;
let matchedRule = null;
for (let r = 0; r < rules.length && !picked; r++) {
  const idx = candidates.findIndex(m => score(m)[r]);
  if (idx !== -1) { picked = candidates[idx]; matchedRule = rules[r]; }
}

// ---------- 6) Return result in fixed shape ----------
if (!picked?.user?.id) {
  return done({
    error: 'no_match',
    message: `No match for "${raw}" in ${members.length} members.`,
    query: raw,
    candidateCount: members.length,
    userId: null,
    matchedField: null,
    matchedValue: null,
  });
}

let matchedValue = null;
if (matchedRule.endsWith('nick'))         matchedValue = picked.nick ?? null;
if (matchedRule.endsWith('global_name'))  matchedValue = picked.user?.global_name ?? null;
if (matchedRule.endsWith('username'))     matchedValue = picked.user?.username ?? null;

return done({
  ok: true,
  error: null,
  message: null,
  query: raw,
  candidateCount: members.length,
  userId: picked.user.id,
  matchedField: matchedRule,
  matchedValue,
});

